turtle = {"x": 0, "heading": 0, "pen": "down"}
log = []


def fd(distance):
    old_x = turtle["x"]
    turtle["x"] += distance
    if turtle["pen"] == "down":
        log.append(("draw", old_x, turtle["x"]))
    else:
        log.append(("move", old_x, turtle["x"]))


def rt(degrees):
    turtle["heading"] = (turtle["heading"] - degrees) % 360
    log.append(("right", degrees, turtle["heading"]))


def penup():
    turtle["pen"] = "up"
    log.append(("pen", "up"))


def pendown():
    turtle["pen"] = "down"
    log.append(("pen", "down"))


def repeat(k, fn):
    if k > 0:
        fn()
        repeat(k - 1, fn)


repeat(4, lambda: (fd(100), rt(90)))

penup()
fd(50)
pendown()

print(turtle)
